        { __m256d _lo = _mm256_load_pd(&in[2*(2*K+k)]);
          __m256d _hi = _mm256_load_pd(&in[2*(2*K+k+2)]);
          r2r = _mm256_permute4x64_pd(_mm256_shuffle_pd(_lo,_hi,0x0), 0xD8);
          r2i = _mm256_permute4x64_pd(_mm256_shuffle_pd(_lo,_hi,0xF), 0xD8); }
        const __m256d x2r = _mm256_fmsub_pd(r2r,tw2r,_mm256_mul_pd(r2i,tw2i));
