        const __m256d opr = _mm256_add_pd(x1r,x5r), opi = _mm256_add_pd(x1i,x5i);
        const __m256d oqr = _mm256_sub_pd(x1r,x5r), oqi = _mm256_sub_pd(x1i,x5i);
